   110→  case FloatTyID: return APFloat::IEEEsingle();
   111→  case DoubleTyID: return APFloat::IEEEdouble();
   112→  case X86_FP80TyID: return APFloat::x87DoubleExtended();
   113→  case FP128TyID: return APFloat::IEEEquad();
